package trackerweb

import (
	"html/template"

	"github.com/labstack/echo/v5"
)

var pages = template.Must(template.New("pages").Parse(loginTemplate + dashboardTemplate + projectTemplate + errorTemplate))

func render(ctx *echo.Context, status int, name string, data any) error {
	ctx.Response().Header().Set("Content-Type", "text/html; charset=utf-8")
	ctx.Response().WriteHeader(status)
	return pages.ExecuteTemplate(ctx.Response(), name, data)
}

const loginTemplate = `{{define "login"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>SavewebHQ sign in</title><link rel="stylesheet" href="/assets/admin.css"></head><body class="login-body"><main class="login"><div class="brand">SavewebHQ</div><h1>Administration</h1><a class="button primary" href="/auth/github/start">Sign in with GitHub</a></main></body></html>{{end}}`

const dashboardTemplate = `{{define "dashboard"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Projects · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/admin">SavewebHQ</a><div class="account"><span>{{.User.GitHubLogin}}</span><form method="post" action="/logout"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="quiet" type="submit">Sign out</button></form></div></header><main><div class="page-title"><div><h1>Projects</h1><p>{{len .Projects}} registered</p></div></div><section class="table-wrap"><table><thead><tr><th>Project</th><th>Status</th><th>Todo</th><th>WIP</th><th>Done</th><th>Failed</th><th>Exhausted</th></tr></thead><tbody>{{range .Projects}}<tr><td><a href="/admin/projects/{{.ID}}"><code>{{.ID}}</code></a></td><td><span class="status {{.Status}}">{{.Status}}</span></td><td>{{index .JobCounts "todo"}}</td><td>{{index .JobCounts "wip"}}</td><td>{{index .JobCounts "done"}}</td><td>{{index .JobCounts "failed"}}</td><td>{{index .JobCounts "reset_exhausted"}}</td></tr>{{else}}<tr><td colspan="7" class="empty">No projects</td></tr>{{end}}</tbody></table></section><section class="form-band"><h2>Create project</h2><form method="post" action="/admin/projects" class="inline-form"><input type="hidden" name="csrf" value="{{.CSRF}}"><label>Project ID<input name="project_id" maxlength="128" pattern="[A-Za-z0-9._:-]+" required></label><label>Status<select name="status"><option value="active">Active</option><option value="draining">Draining</option><option value="archived">Archived</option></select></label><button class="primary" type="submit">Create project</button></form></section></main></body></html>{{end}}`

const projectTemplate = `{{define "project"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{{.Project.ID}} · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/admin">SavewebHQ</a><div class="account"><span>{{.User.GitHubLogin}}</span><form method="post" action="/logout"><input type="hidden" name="csrf" value="{{.CSRF}}"><button class="quiet" type="submit">Sign out</button></form></div></header><main><div class="breadcrumbs"><a href="/admin">Projects</a><span>/</span><code>{{.Project.ID}}</code></div><div class="page-title"><div><h1>{{.Project.ID}}</h1><p>Created {{.Project.CreatedAt}} · Updated {{.Project.UpdatedAt}}</p></div><form method="post" action="/admin/projects/{{.Project.ID}}/status" class="status-form"><input type="hidden" name="csrf" value="{{.CSRF}}"><select name="status"><option value="active" {{if eq .Project.Status "active"}}selected{{end}}>Active</option><option value="draining" {{if eq .Project.Status "draining"}}selected{{end}}>Draining</option><option value="archived" {{if eq .Project.Status "archived"}}selected{{end}}>Archived</option></select><button type="submit">Save status</button></form></div><section class="metrics"><div><span>Todo</span><strong>{{index .Project.JobCounts "todo"}}</strong></div><div><span>WIP</span><strong>{{index .Project.JobCounts "wip"}}</strong></div><div><span>Done</span><strong>{{index .Project.JobCounts "done"}}</strong></div><div><span>Failed</span><strong>{{index .Project.JobCounts "failed"}}</strong></div><div><span>Exhausted</span><strong>{{index .Project.JobCounts "reset_exhausted"}}</strong></div></section><section class="form-band"><h2>Enqueue jobs</h2><form method="post" action="/admin/projects/{{.Project.ID}}/jobs"><input type="hidden" name="csrf" value="{{.CSRF}}"><label>Job batch<textarea name="jobs_json" rows="12" spellcheck="false" required>[]</textarea></label><div class="actions"><button class="primary" type="submit">Enqueue jobs</button></div></form></section></main></body></html>{{end}}`

const errorTemplate = `{{define "error"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Request failed · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body class="login-body"><main class="login"><div class="brand">SavewebHQ</div><h1>Request failed</h1><p>{{.Message}}</p><a class="button" href="/">Return</a></main></body></html>{{end}}`

const adminCSS = `:root{color-scheme:light;--ink:#17201c;--muted:#66716b;--line:#d9dfdc;--paper:#fff;--wash:#f4f6f5;--green:#176b45;--green-dark:#0e4e31;--amber:#8a5a00;--red:#a12b2b}*{box-sizing:border-box}body{margin:0;background:var(--wash);color:var(--ink);font:14px/1.45 ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;letter-spacing:0}a{color:var(--green-dark)}header{height:58px;padding:0 max(20px,calc((100vw - 1180px)/2));display:flex;align-items:center;justify-content:space-between;background:var(--ink);color:#fff}.brand{font-size:18px;font-weight:750;color:inherit;text-decoration:none}.account{display:flex;align-items:center;gap:16px}.account form{margin:0}main{max-width:1180px;margin:0 auto;padding:32px 20px 72px}.page-title{display:flex;align-items:flex-end;justify-content:space-between;gap:24px;margin-bottom:24px}h1{font-size:28px;line-height:1.15;margin:0 0 4px}h2{font-size:18px;margin:0 0 18px}.page-title p,.login p{margin:0;color:var(--muted)}.table-wrap{overflow:auto;background:var(--paper);border:1px solid var(--line)}table{width:100%;border-collapse:collapse;white-space:nowrap}th,td{text-align:left;padding:12px 14px;border-bottom:1px solid var(--line)}th{font-size:12px;text-transform:uppercase;color:var(--muted);background:#f8f9f8}tbody tr:last-child td{border-bottom:0}code,textarea{font-family:ui-monospace,SFMono-Regular,Consolas,monospace}.status{font-weight:650}.status.active{color:var(--green)}.status.draining{color:var(--amber)}.status.archived{color:var(--muted)}.empty{text-align:center;color:var(--muted);padding:32px}.form-band{margin-top:32px;padding-top:28px;border-top:1px solid var(--line)}form.inline-form,.status-form{display:flex;align-items:end;gap:12px;flex-wrap:wrap}label{display:grid;gap:6px;font-weight:650}input,select,textarea,button,.button{min-height:38px;border:1px solid #aeb8b3;border-radius:5px;background:#fff;color:var(--ink);font:inherit;letter-spacing:0;padding:8px 10px}input{min-width:240px}textarea{width:100%;resize:vertical;line-height:1.5}button,.button{display:inline-flex;align-items:center;justify-content:center;font-weight:700;text-decoration:none;cursor:pointer}.primary{background:var(--green);border-color:var(--green);color:#fff}.primary:hover{background:var(--green-dark)}.quiet{min-height:32px;padding:5px 9px;background:transparent;border-color:#59635e;color:#fff}.breadcrumbs{display:flex;gap:8px;color:var(--muted);margin-bottom:18px}.metrics{display:grid;grid-template-columns:repeat(5,minmax(110px,1fr));border:1px solid var(--line);background:var(--paper)}.metrics div{padding:16px;border-right:1px solid var(--line)}.metrics div:last-child{border-right:0}.metrics span{display:block;color:var(--muted);font-size:12px;text-transform:uppercase}.metrics strong{display:block;font-size:25px;margin-top:4px}.actions{margin-top:12px}.login-body{min-height:100vh;display:grid;place-items:center}.login{width:min(420px,calc(100% - 40px));padding:36px;border-top:4px solid var(--green);background:var(--paper);box-shadow:0 8px 24px rgba(23,32,28,.1)}.login h1{margin:18px 0 24px}.login .button{margin-top:22px}@media(max-width:720px){header{padding:0 16px}main{padding:24px 16px 56px}.page-title{align-items:flex-start;flex-direction:column}.metrics{grid-template-columns:repeat(2,1fr)}.metrics div{border-bottom:1px solid var(--line)}.inline-form label,.inline-form input,.inline-form select,.inline-form button{width:100%}.account span{display:none}}`
